import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer';
import { CorporationRanksParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/CorporationRankParser';

export class CorporationRanksEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: Function) {
        super(callback, CorporationRanksParser);
        // console.log('[🏷️] CorporationRanksEvent initialized');
    }

    public getParser(): CorporationRanksParser {
        return this.parser as CorporationRanksParser;
    }
}
